                  CREATE View [SSRS].[JuniorLeague_SeasonCurrLast_STD]    as  Select    League_ID,    Name,    Year_of_Fixture,    Sum([No Result])[No Result],     Sum(Abandoned  )Abandoned  ,   Sum(Cancelled  )Cancelled  ,   Sum(Conceded   )Conceded   ,   Sum(InProgress )InProgress ,   Sum(Win     )Win         FROM   (  SELECT Case [League_ID] When 8205 then 15363 Else League_ID END League_ID        ,Case [League_ID] When 15363 then 'Northumberland and Tyneside Senior Cricket League' Else REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' ') END AS Name         ,[year_of_Fixture]        ,[MonthofFixture]        ,[No Result]        ,[Abandoned]        ,[Cancelled]        ,[Conceded]        ,[InProgress]        ,[Win]      FROM [SSRS].[JuniorLeagues_SeasonTD_2022] a    UNION      Select Case [League_ID] When 8205 then 15363 Else League_ID END        ,Case [League_ID] When 8205 then 'Northumberland and Tyneside Senior Cricket League' Else REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' ') END AS Name         ,[year_of_Fixture]        ,[MonthofFixture]        ,[No Result]        ,[Abandoned]        ,[Cancelled]        ,[Conceded]        ,[InProgress]        ,[Win]    FROM   [SSRS].[JuniorLeagues_SeasonTD_2021]       )A     WHere MonthofFixture <=  DATEPART(month,getdate())-1     group by League_ID,    Name,    Year_of_Fixture                